import type { Configuration } from "@azure/msal-browser";
import { LogLevel } from "@azure/msal-browser";

// Replace with your actual Entra ID app registration values
const clientId = import.meta.env.VITE_AZURE_CLIENT_ID || "YOUR_APP_CLIENT_ID";
const tenantId = import.meta.env.VITE_AZURE_TENANT_ID || "7fb15bf6-9cea-4c72-89bd-1ab9f16eec8e";
const redirectUri = import.meta.env.VITE_REDIRECT_URI || window.location.origin;

export const msalConfig: Configuration = {
  auth: {
    clientId,
    authority: `https://login.microsoftonline.com/${tenantId}`,
    redirectUri,
    postLogoutRedirectUri: redirectUri,
  },
  cache: {
    cacheLocation: "localStorage",
  },
  system: {
    loggerOptions: {
      loggerCallback: (level, message, containsPii) => {
        if (containsPii) return;
        if (level === LogLevel.Error) console.error(message);
        if (level === LogLevel.Warning) console.warn(message);
      },
      logLevel: LogLevel.Warning,
    },
  },
};

export const loginRequest = {
  scopes: ["User.Read", `api://${clientId}/access_as_user`],
};

export const apiScopes = {
  scopes: [`api://${clientId}/access_as_user`],
};
