
import {
  Dropdown,
  Option,
  makeStyles,
  tokens,
  Spinner,
  Text,
} from "@fluentui/react-components";
import { Building24Regular } from "@fluentui/react-icons";
import type { TenantListItem } from "../types";
import type { TenantSelection } from "../hooks/useTenantContext";

const useStyles = makeStyles({
  container: {
    display: "flex",
    alignItems: "center",
    gap: "8px",
    paddingLeft: "12px",
    paddingRight: "12px",
  },
  icon: {
    color: tokens.colorBrandForeground1,
  },
  dropdown: {
    minWidth: "220px",
  },
});

interface TenantPickerProps {
  tenants: TenantListItem[];
  loading?: boolean;
  selectedTenant: TenantSelection;
  onTenantChange: (tenant: TenantSelection) => void;
}

export function TenantPicker({
  tenants,
  loading,
  selectedTenant,
  onTenantChange,
}: TenantPickerProps) {
  const styles = useStyles();

  if (loading) {
    return (
      <div className={styles.container}>
        <Spinner size="tiny" />
        <Text size={200}>Loading tenants...</Text>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      <Building24Regular className={styles.icon} />
      <Dropdown
        className={styles.dropdown}
        value={selectedTenant.displayName}
        selectedOptions={[selectedTenant.tenantId]}
        onOptionSelect={(_e, data) => {
          if (data.optionValue === "all") {
            onTenantChange({ tenantId: "all", displayName: "All Tenants" });
          } else {
            const tenant = tenants.find((t) => t.tenantId === data.optionValue);
            if (tenant) {
              onTenantChange({
                tenantId: tenant.tenantId,
                displayName: tenant.displayName,
              });
            }
          }
        }}
        size="small"
      >
        <Option value="all">All Tenants</Option>
        {tenants
          .filter((t) => t.status === "Active")
          .map((t) => (
            <Option key={t.tenantId} value={t.tenantId}>
              {t.displayName}
            </Option>
          ))}
      </Dropdown>
    </div>
  );
}
